mapper.select:
SELECT t.name, t.color, COUNT(*) AS cnt
FROM tag_rel tr
JOIN tag t ON tr.tag_id = t.id
WHERE t.user_id = #{userId}
    AND tr.created_at >= #{since}
GROUP BY t.id, t.name, t.color
ORDER BY cnt DESC LIMIT #{limit}

SELECT id, module, action, content, business_id, created_at
FROM audit_log
WHERE operator_id = #{userId}
    AND created_at >= #{since}
ORDER BY created_at DESC LIMIT #{limit}

SELECT DISTINCT date FROM study_record
    WHERE user_id = #{userId} AND is_deleted = 0 AND date >= #{since}
UNION
SELECT DISTINCT DATE(created_at) FROM note_note
    WHERE user_id = #{userId} AND is_deleted = 0 AND created_at >= #{since}
UNION
SELECT DISTINCT DATE(created_at) FROM todo_task
    WHERE user_id = #{userId} AND created_at >= #{since}
UNION
SELECT DISTINCT DATE(created_at) FROM reading_record
    WHERE user_id = #{userId} AND is_deleted = 0 AND created_at >= #{since}
ORDER BY 1 DESC

SELECT COUNT(*) FROM note_note
WHERE user_id = #{userId} AND is_deleted = 0
    AND created_at >= #{start} AND created_at < #{end}

SELECT COALESCE(SUM(total_duration), 0) FROM reading_record
WHERE user_id = #{userId} AND is_deleted = 0
    AND created_at >= #{start} AND created_at < #{end}

SELECT COUNT(*) FROM todo_task
WHERE user_id = #{userId}
    AND is_done = 1
    AND updated_at >= #{start} AND updated_at < #{end}

SELECT COUNT(*) FROM todo_task
WHERE user_id = #{userId}
    AND (created_at >= #{start} AND created_at < #{end})
